const express = require('express');
const app = express();

app.use(express.json());

// Simulated user database
const users = {
  '1': {
    id: '1',
    username: 'johndoe',
    email: 'john@example.com',
    firstName: 'John',
    lastName: 'Doe',
    bio: 'Software developer',
    avatar: 'https://example.com/avatars/johndoe.png',
    createdAt: '2023-01-15T10:30:00Z',
    isPrivate: false
  },
  '2': {
    id: '2',
    username: 'janedoe',
    email: 'jane@example.com',
    firstName: 'Jane',
    lastName: 'Doe',
    bio: 'UX Designer',
    avatar: 'https://example.com/avatars/janedoe.png',
    createdAt: '2023-03-22T14:00:00Z',
    isPrivate: true
  },
  '3': {
    id: '3',
    username: 'bobsmith',
    email: 'bob@example.com',
    firstName: 'Bob',
    lastName: 'Smith',
    bio: 'DevOps Engineer',
    avatar: 'https://example.com/avatars/bobsmith.png',
    createdAt: '2023-06-10T08:45:00Z',
    isPrivate: false
  }
};

// Simulated authentication middleware (assumes it has already run)
const simulatedAuthMiddleware = (req, res, next) => {
  // In production, this would be replaced by real auth middleware
  req.user = {
    id: '1',
    username: 'johndoe',
    role: 'user'
  };
  next();
};

app.use(simulatedAuthMiddleware);

// Helper to build a public profile (excludes sensitive fields)
const getPublicProfile = (user) => {
  const { email, ...publicFields } = user;
  return publicFields;
};

// Helper to build a full profile (includes all fields for the owner)
const getFullProfile = (user) => {
  return { ...user };
};

// GET /api/users/:userId - Get user profile by user ID
app.get('/api/users/:userId', (req, res) => {
  try {
    const { userId } = req.params;

    // Validate userId parameter
    if (!userId || typeof userId !== 'string' || userId.trim() === '') {
      return res.status(400).json({
        success: false,
        error: 'Invalid user ID parameter'
      });
    }

    const user = users[userId];

    // Check if user exists
    if (!user) {
      return res.status(404).json({
        success: false,
        error: 'User not found'
      });
    }

    const isOwner = req.user && req.user.id === userId;

    // If the requesting user is the profile owner, return full profile
    if (isOwner) {
      return res.status(200).json({
        success: true,
        data: getFullProfile(user)
      });
    }

    // If the profile is private and the requester is not the owner
    if (user.isPrivate) {
      return res.status(403).json({
        success: false,
        error: 'This profile is private'
      });
    }

    // Return public profile for other users
    return res.status(200).json({
      success: true,
      data: getPublicProfile(user)
    });

  } catch (error) {
    console.error('Error fetching user profile:', error);
    return res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

// GET /api/users - Get all public user profiles
app.get('/api/users', (req, res) => {
  try {
    const { page = 1, limit = 10, search } = req.query;

    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);

    if (isNaN(pageNum) || pageNum < 1 || isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
      return res.status(400).json({
        success: false,
        error: 'Invalid pagination parameters. Page must be >= 1, limit must be between 1 and 100.'
      });
    }

    let userList = Object.values(users).map((user) => {
      const isOwner = req.user && req.user.id === user.id;
      if (isOwner) {
        return getFullProfile(user);
      }
      if (user.isPrivate) {
        return {
          id: user.id,
          username: user.username,
          isPrivate: true
        };
      }
      return getPublicProfile(user);
    });

    // Optional search by username or name
    if (search) {
      const searchLower = search.toLowerCase();
      userList = userList.filter((user) =>
        (user.username && user.username.toLowerCase().includes(searchLower)) ||
        (user.firstName && user.firstName.toLowerCase().includes(searchLower)) ||
        (user.lastName && user.lastName.toLowerCase().includes(searchLower))
      );
    }

    const total = userList.length;
    const startIndex = (pageNum - 1) * limitNum;
    const paginatedUsers = userList.slice(startIndex, startIndex + limitNum);

    return res.status(200).json({
      success: true,
      data: paginatedUsers,
      pagination: {
        total,
        page: pageNum,
        limit: limitNum,
        totalPages: Math.ceil(total / limitNum)
      }
    });

  } catch (error) {
    console.error('Error fetching users:', error);
    return res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

// GET /api/me - Get the authenticated user's own profile
app.get('/api/me', (req, res) => {
  try {
    if (!req.user || !req.user.id) {
      return res.status(401).json({
        success: false,
        error: 'Unauthorized'
      });
    }

    const user = users[req.user.id];

    if (!user) {
      return res.status(404).json({
        success: false,
        error: 'Authenticated user profile not found'
      });
    }

    return res.status(200).json({
      success: true,
      data: getFullProfile(user)
    });

  } catch (error) {
    console.error('Error fetching own profile:', error);
    return res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;